begin;

insert into public.lesson_records (lesson_record_id, student_id, course_id, staff_id, lesson_date, start_time, end_time, title, content, homework, memo) values
  ('03be7a39-c2c4-5c5d-aaad-68f792c0f934', '5c9bb4b1-2f4b-5e1e-9f34-bcc4d0dea21a', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-04-11', '17:30:00', null, '通常 / アレンジ大賞続き', 'アレンジ大賞というよりは、ほぼオリジナル作品になりました。 メッセージを使ったときのスクリプトの扱いに苦戦していました。音が繰り返しながれてしまう、変数が変わり続けてしまうのを工夫して改善していました。プログラムの実行順序について気を配れていました。 いろいろな要素の詰まった作品に仕上がりました。', null, null),
  ('e9900a20-4952-5276-863f-7c456678fa5d', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-04-11', '17:30:00', null, '通常 / アレンジ大賞続き', '邪魔者の追加に取り組んでいました。また、マリオやルイージの攻撃のコード、変数の使われ方に注目していました。弾丸の方向に注意して、プログラムでうまくコントロールすることもできています。 少ない時間のアレンジ大賞になりましたが、集中して黙々と取り組んでいました。また金曜日に取り組み、完成させる予定です。', null, '盛り上がり: 時間中、1度も席を立たないで取り組んでいました。とても集中できていました！'),
  ('666d9a1b-b0e1-5956-bf2e-4c4b1046caf7', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-04-11', '16:30:00', null, '通常 / ジャンプゲームアレンジバージョンor雲に隠れた太陽 基本操作の確認、変数の使い方', 'ジャンプ、コスチューム変化などの基本的な動作に加えて変数を少し工夫して使ったゲームです。さらちゃんにも取り組んでもらいました。 条件分岐の考え方が苦手なようです。そこに変数も加わると特に混乱してしまうようでした。しかし以前と違ってプログラムを見たときに「これじゃダメじゃない？」とブロックをみて指摘できるようになってきました。ゲームの大枠は完成しました。最後にプレイしたときは本人も満足そうでした。', null, 'タイピング: 高得点でした！集中して取り組めていました！
盛り上がり: コスチュームの変化のタイミングにこだわっていました！'),
  ('2a633942-9340-5260-89ec-4a99f6b6478a', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-04-11', '16:30:00', null, '通常 / アレンジ大賞初級に挑戦', '終わりの画面を出す=終わりのコードを探すところから始めました。一応どのコードが何をしているかは読めているようで、「ここで背景を変える」というのも自分で探せました。 この作品にも少し飽きてきていたのか、終わりの背景が出せたら「もうできた！」と立ち上がっていましたが、お絵描きやコスチュームのアレンジが好きそうなので、「マイナスむらっちを作っては？」との提案をしたところ、かなりノリノリでマイナスむらっちスプライトを作っていました。マイナスむらっちのおかげで、スコアの変数も見直し確認することができました。 アレンジ大賞提出後、「ゲームなら勉強してもいい」とのことで、単元別演習F-1「おにごっこ」を作成しました。マウスポインタを追いかけるためには、どちらを向いて何をすればよいか、というヒントは必要でしたが、その後はカードの裏を見ずに作成することができました。 実際にドリルを完成させて遊んでみると、すぐにゲームオーバーになるため、しょうたくんなりに工夫して初期座標や大きさを変更するブロックを最初に入れ、長く遊べるように仕上げていました。', null, '盛り上がり: コスチュームのアレンジは本当に楽しそうで、そのおかげか、一気にやる気が出ていました。 作品を2つ仕上げられたのが嬉しかったようで、お父さんに熱心に紹介していました。'),
  ('a20ca216-abce-50a8-b075-1bb0dc547e51', '7d01236e-620e-5177-a6f4-af325a582aae', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2023-04-04', '17:30:00', null, '通常 / アレンジ大賞、むらっちたたきのアレンジ。', '★本日のポイント どうなったらキジムンが現れるか（＆同時に背景が変わるか） 現時点で動きません。 ゲームのアレンジのイメージは以下 １）むらっちたたきでスコアが「30」になったら ２）背景を変えて（＝Boardwalk）キジムンが登場 ↑但し、このゲームの流れを恐らく今日は忘れている可能性が大です。 ◆メッセージの使い方があいまい。 「スタート」のメッセージでむらっちが動く ⇒キジムンはその間隠れる ⇒全て「緑の旗が押されたら」スタートすると思っていたので、「スタート」メッセージで、誰がどう動いているのかきちんと確認できていない様子（ササ～～とみているだけなので）', '２点、今後整えたいスキルがあります。 ①メッセージの使い方（特にメインキャラクターが「緑の旗以外のメッセージで起動する」ことについて） ②スコアという変数の使い方。思い出したものの、「変数」として仕えていない。そのため、今回のアレンジ作品でスコアをつけているものの、「変数」として何かをコントロールしていない。たぶん。今回の仕上げには間に合いませんが、ここを追々。', '盛り上がり: 最初、キジムンのスプライトを選び、コスチュームをいじっていたところ、髪の毛とスカートが分解され、スッポンポン頭ツルツルになり、これを非常に気に入りました。今までで一番の笑顔を見せてくれました(#^.^#) アレンジのアイデア自体は浮かんでいなかったので、話しをしながら飛び出しながら髪の毛とスカートがなくなるように設定しようといことになりました。'),
  ('403f30c6-b8e8-5709-8f21-32440537fb36', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-04-08', null, null, '通常 / 教室に慣れる、基本のコードを確かめる', 'テキストの内容を順にやっていったのですが、指示が分かればあまりテキストを見なくても感覚的にできていました。座標をなめらかに変えていくのが好きだったみたいで何回かやっていました。最初はアルくんやむらっちを動かしましたが、自分の名前のアルファベットでもやりました。', null, '時間帯: その他
タイピング: わりとスムーズに打てていました。
盛り上がり: 作ったり動かしたりすることがとても楽しいという感じでした。'),
  ('671b9095-0147-5095-afde-f422ea937be8', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '4fb853b8-7d59-5565-9d96-060872e780d1', '2023-04-08', null, null, '通常 / 教室のルール説明', 'とにかく落ち着きがなかったです。 「こう先生」が頑張って教えているのにも関わらず、聞く耳を持たないというような様子でした。ほぼこちらが指示して、操作をしている状態だったのでおそらく理解はしていませんん。 次回「ゆき先生」が親御さんに相談するそうです。 相談後に授業の方針を決めていくと仰っていました。', '授業の目的を教える→やる範囲を決めた所まで行ってもらう→自由時間を与える。 上記のような方法で行う予定です。', '時間帯: その他
タイピング: 落ち着いて行っていました
盛り上がり: ゲーム感覚でPCの操作をする様子がとても楽しそうでした。'),
  ('7d7bb1ae-523a-5549-b0d8-9c83076d8d0a', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-04-08', null, null, '通常 / 教室に慣れる、基本操作コースからスキルの確認', '経験があるとのことだったので、お題を出して作成という繰り返しでスキルチェックをしました。 基本操作コース1枚目のスキルはほぼ確認できました。 上下左右の動きは、先に向きを指定してから〇歩うごく、の形式で作成していたので、座標で動かす方法も一緒に確認し、それぞれの利点のチェックをしました。 音や画像は、ネット上から検索して持ってくる癖がついています。公開する作品を作成する段階で、著作権の話などもしておきたいところです。 内容的には初歩でしたが、「これできる？」と問いかけると「できる！」と嬉しそうに反応して、できあがると声をかけて、「見て見て！」という感じで楽しんでくれているようでした。', 'ピンポンゲームでスキルや癖のチェック', '時間帯: その他
タイピング: タイピングはそれほど得意なわけではないと言ってはいましたが、それなりの正誤率を出せていました。
盛り上がり: 簡単な内容でも、ばかにしたようなそぶりはなく、基本的に「それもできるよ！」と嬉しそうに取り組んでくれました。 スキルの穴埋めをしながらいろいろ作れるようになっていこうね、という目的にも納得してくれているようで、時間いっぱい熱心にできていました。'),
  ('1f5e9026-183c-5a2b-b522-fd8a9761e07f', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-04-08', null, null, '通常 / アレンジ大賞', 'お手本を再現するのは前回できたので、今回はアレンジに入りました。疲れた様子だったので、休憩をはさんだりしながら進めました。アイデアがなかなか思いつかなかったので、自分が今までに作ってきたゲームを参考にすることを勧めました。最終的には「君のスコアは〇点だよ」と伝える恐竜を出すというアレンジを加えました。恐竜のセリフは文字列の連結を活用して作りました。', null, '時間帯: その他
タイピング: 最初はふざけていましたが、「その記録を書くことになっちゃうけど大丈夫～？」などと言うとまじめにやっていました。
盛り上がり: 友達のそうたくんに見せようという気持ちでなんとか頑張りました。'),
  ('0ef59cf6-37b6-555f-be88-d4f8a2e3761b', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '4fb853b8-7d59-5565-9d96-060872e780d1', '2023-04-08', null, null, '通常 / アレンジ大賞作品の作成', '作品のイメージで悩んでいた。 デザインで悩んでいたので、デザインの提案を与えたが微妙な反応を取られたので上手く距離を取りながら見守っていました。結果自分で、解決が出来ていたみたいなので結果として問題なかったです。', 'アルスパーク/【アレンジ大賞】初級＿むらっちたたき→コンセプトにズレが出てきているので、そのズレを一緒に直そうと帰りに「まみ先生」が言ってくれたそうです。', '時間帯: その他
タイピング: 通常通り行っていました
盛り上がり: デザインを一所懸命に考えていた様子がとても、ワクワクしているように見えました。'),
  ('1cbd9eb7-3293-51c7-9edd-ca4c290c19f2', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-04-08', null, null, '通常 / アレンジ大賞作品の作成', '返事を焦らせなければ、ずいぶんとしゃべってくれるようになりました。やりたいことについても、だいぶ文章で説明できるようになってきました。 スコアが基準に満たなかった時に「ゲームオーバー」にしたかったようですが、最初からゲームオーバーになってしまうバグがあったので、実行中のスクリプトが強調されていることを伝え、スタート直後に「ゲームオーバー」メッセージが送信されてしまっていることを確認してメッセージ送信スクリプトを見直す、という手順を一緒に学習しました。 元のスクリプトでは、ゲームスタート時に「クリアの条件ではない」ため「でなければゲームオーバー」の条件に当てはまってしまい、ゲーム開始時からゲームオーバーの状態になってしまっていることを、一つずつコードを確認しながら理解できました。 ゲームクリアとゲームオーバーの条件を紙に書きだして整理して、「タイムが1より小さくなるまで待つ」「スコアが30より大きいときと、でなければ」の形にまとめられることを確認してから作成したところ、なつめちゃんも納得しながら修正することができていました バグが解決できてすっきりしたのか、他にやりたいことをいろいろ話してくれて、ダミーのくまちゃんを作ったり、音楽を入れたりとそれなりのアレンジができました。', '今回の作品のテストプレイと見直しをして提出する予定', '時間帯: その他
タイピング: これまでと比べて良い結果が出て嬉しそうでした
盛り上がり: まだ少し自信がないのか、間違えたくないのか、新しいコードを作成するときに見ていて欲しがる傾向はありますが、やりたいことを口にしたり、講師が席を離れた時は自分なりに進めてみたりと積極性が見られるようになってきました。 ゲームのアレンジも、現時点でのなつめちゃんの持つスキルはかなり出すことができていて、本人も満足そうでした。'),
  ('f1c3617a-5d93-5f6f-9116-e8353323b28f', '13bd73d0-f535-5291-8362-6712e5cd7384', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-04-07', '16:30:00', null, '通常 / アレンジ大賞の作成', '前回作りかけのアルくんはボーナス得点でかなり難しめ設定で作っていました。スタート画面はアルくんの説明だったり、ややスプラッタなことも表現できていました。作業中はアイデア止まることなく黙々と作り上げていました。そして、スコアが上がるごとに背景も変わっていき、どこまで背景を楽しませることができるか感じられるアレンジになっていました。', null, 'タイピング: スコアが伸びてきました。
盛り上がり: アレンジでずっと集中して取り組めていました。'),
  ('e13c8562-2125-5384-8a74-88ca2d8ea6d0', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-04-07', '16:30:00', null, '通常 / アレンジ大賞作成', '週が空いたこともあり、アレンジ大賞の作品はどうゆうことをしたか思い出しずらく、背景をうさぎにあったものに変えて、早めに作品を切り上げました。 次に、イライラゲームの作品を作りました。動画を見ながらの作成でしたが、ところどころにアレンジも同時に作りながらやっていました。次週で完成できそうです。', null, 'タイピング: 気が付いたら何度もやっていました'),
  ('0c3e7917-7265-5f8c-a9c1-68062203ccc0', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-04-07', '18:40:00', null, '通常 / アレンジ大賞上級アレンジへ', 'HPの表示が重なる。剣の絵なのに銃が撃ててしまう、などのバグの修正に取り組んでいました。 ひとりごと多くてもごもごしてくれて考えてくれてるから、話しかけ時が難しい！！！！自分で原因を考えられていました。原因を探すポイントについて共有しました。見つけられないところもあったので、次回取り組みます！！', '完成させる！！', null),
  ('b6a07a3b-2700-5919-b6fe-7a55e627838f', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-04-07', '17:30:00', null, '通常 / アレンジ大賞 マリオのアレンジ', '自分が作りたいというアイディアが多く、そして自力でコードが書けている状態、 またスプライト同士のリレーション問題も干渉せずできていました。 一個だけボーナスタイムの時に速度が早くなる〜という問題部分がわからなかっただけで、大和先生にヒントをもらい、理解をしていたようでした。', null, 'タイピング: なし
盛り上がり: きちんと自分がやりたい動きをコードで「どのように書いたらいいか？」が理解できていて素晴らしい！そしてちゃんと動作確認など、コードを書いたらすぐ見直すという部分も本人にとってはとても楽しい時間になっていたようでした。'),
  ('4e16044a-9e8e-5295-8c1c-101137c4fa15', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-04-07', '17:30:00', null, '通常 / アレンジ大賞 マリオを全部写す→アレンジに向かう', '今日はコードを写し終わるというところがメインだったのですが、どうしてもコードがわからないという言葉を連続。 途中で嫌になってしまったようで、結局今日は途中で帰宅となりました。 どうやらどのコードのブロックを写しているのか、コードの読み取り自体が嫌になってしまったようです。次回までのやり方を少し考えないといけないフェーズに来ているのかもしれません。 今はネガティブになっているので、何を言っても響かない感じ', null, 'タイピング: なし'),
  ('5bc8d7fa-4828-5058-8695-8b53104d619c', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-04-07', '16:30:00', null, '通常 / アレンジ大賞 初級 バグの部分を潰す', 'ボーナスタイムの時に出るむらっちや、クローンの使い方というのが曖昧だった様子で、同じコードを単純に写していました。そのため、スプライト同士が干渉しあってバグにつながっていたりしました。 また、アイディア自体は良いもののスプライト同士のリレーションの整合性不明確になってしまっていたため、出てこないでほしい時にむらっちが出てき続けるというバグにもつながっていました。 以上の点を紙に書いて、もう一度コードの書き直しをしてもらい、なんとか途中までは出来上がっていた様子です。', null, 'タイピング: スコアがだいぶ伸びてきて本人も結果にとても満足していた様子でした。
盛り上がり: 来週完成できるかな？'),
  ('7bde6678-9af9-5855-818c-81a1f0ae9bec', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-04-07', '16:30:00', null, '振替 / アレンジ大賞 初級でアレンジをするという目標を立てて、来週までに完成させる', '最初に全てを移して、どのようなアレンジをするか？を考える日にしていました。途中まで移し終えたところで、保存を間違ってしまったそうで、やったところまでが全て水の泡となる事態に・・・ もう一度最初から移して、来週アレンジを完成させるということで話がつきました。 やってみたい内容は写し終えたら考えるということだったので今日はコード自体を写すことで終わってしまいました。', null, 'タイピング: なし'),
  ('360d6870-e578-5b25-9d60-165a9d484a5d', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-04-07', null, null, '通常 / アレンジ大賞初級', '背景を追加してかわいくしました。スペースキーで変わるそうです。最後にスプライトを出すことにしました。方法としてメッセージを使うことを提案しました。メッセージ名も自分でタイプすることができました。表示だけでなく、隠すプログラムも自分でいれることができました。 最後にタイトルを考え、作品を提出しました。集中して取り組むことができていました！', null, '時間帯: その他'),
  ('cf552f2b-75ed-588e-951d-ca64fd119dfd', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-04-07', '17:30:00', null, '通常 / アレンジ大賞に挑戦', 'どうしても中級に取り組みたかったそうなので、リミックスして取り組みました。「中心にスプライトを置いて上下に動かしたい」とのことでした。y座標の存在は覚えてくれていたのですが、「端についたら跳ね返る」を使う都合上、向きと「〇歩」を使ってもらいました。どれもあまり定着していない様子でした。 その後、あるくんやあるごんがぶつかったら動きがとまるようなプログラムを作りました。ルイージの動きを作るとマリオの動きは自分で作ることが出来ていました。', null, '盛り上がり: 目標が達成できると嬉しそうに遊んでいました！小学校の話もたくさんしてくれました。'),
  ('b12e1a9b-ac77-53b7-96ac-61f6272929cc', 'b2246586-4496-52f9-a825-be2488a00a31', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-04-06', '17:30:00', null, '通常 / アレンジ大賞の作成', '授業前から作っていた作品では、時間がたつごとにバナーが短くなる演出をコスチュームを変えて作れていて、いいアイデアだなと思います他。 後半に、作ったアレンジ大賞のむらっちたたきは、相変わらず正樹君武士が発揮して少し黒いものになったが、背景や音、コスチュームのこだわりは細か宇出来上がっていました。帰るまで、いじっていたので、出来具合だけを見れば、来週はもっと良くなると思います。', null, null),
  ('1f159aaf-d765-59e7-8cec-f7bdc56b4f46', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-04-06', '17:30:00', null, '通常 / アレンジ大賞', '倒す敵である「329」と、触ったらゲームオーバーになる「アルスタッフ」をそれぞれ作りました。キャラクターの見た目もアレンジしました。 元のゲームから背景を変更したので、キャラクターが出てくる座標の範囲を広げたほうがいいということを伝えると、乱数をいじって範囲を広げることができました。 ゲームはこれで完成したそうなので、次回は説明文を考えてエントリーしてもらいます。', 'アレンジ大賞にエントリー', 'タイピング: 「ホームポジションの練習」や「〇行の練習」をいくつかやっていました。
盛り上がり: 教室に通い始めて間もない状態ですが、楽しみながら方向性の決まった作品を作れました。'),
  ('db9946aa-cff1-5d22-a7a1-901a661ad924', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-04-06', '17:30:00', null, '通常 / アレンジ大賞の作成', 'マリオの作品を元の作品をあまり見ずに作っていきました。それぞれ作ったコードごとにコメントでどうゆう動きをすものか示していて、非常に見やすい環境を作っていました。モーションや攻撃判定の条件も独自に悩み止まることなく作れていて、頭がさえていました。あとはエンディングを作れば、一つの作品になると思います。', null, 'タイピング: めちゃくちゃ早い
盛り上がり: 本人もびっくりしたくらいにかなり集中してました。'),
  ('c05d4484-5f2a-53a3-9e29-c341c126b93f', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-04-06', '17:30:00', null, '通常 / アレンジ大賞の作成', 'OPムービーは前回のzoom講義が活かされているような動きのあるものに上がっていました。操作方法の有無もスタート前に尋ねるアレンジも親切心があっていいなと思いました。ジャンプも元の作品のものがパッとしなかったので、何か別のジャンプの仕方をスクラッチで探しながら作っていました。ほかの動きも自力で作っていて素晴らしいです。あと1回で終わると思います。', null, 'タイピング: まずまずチャレンジしていました
盛り上がり: とてもこだわりを感じられました。'),
  ('c0344f85-1173-535a-b55a-52bfef351131', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-04-06', '16:30:00', null, '通常 / アレンジ大賞の基本のコードを作成する', '前回はコスチュームなどのアレンジに時間をかけすぎてしまったので、今回は基本のコードを進めてもらいました。ときどき写経しながら、クローンの生成やスコアの加算をして一通りゲームとして成り立たせることができました。しかしむらっちがすぐ消えてしまい難易度が高すぎると言っていたので、次回はそこの調整から始めたいです。', 'アレンジ大賞続き', 'タイピング: 今日も英単語のタイピングに取り組んでいました。やはり少し難しいらしいです
盛り上がり: 自分で考え、内容を理解しながら作ることができました。'),
  ('e3b02eaa-6be4-5691-9a66-2e1890c5de76', '9fa414fa-958c-54ca-a3e6-d0d8dc0eae6b', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-04-06', '16:30:00', null, '通常 / アレンジ大賞', 'アレンジ大賞の元の最頻はほぼできていたので、アレンジをしました。むらっちをとても増やして、アレンジをすぐ終わろうとしたので、スコアを積み重なって言ったらどうなるのと揺さぶりながらアイデアを渡してあげました。あれこれと悩んンで作っては消したりしてアルくんが追加に動き回り、リアクションを取るようなアレンジを加えてくれました。本人的にもアレンジ作業は満足していたので、完成にさせました。', null, '盛り上がり: 周りのことに気が飛びがちです'),
  ('e03cf476-c3ca-5885-8eca-2fbdd1fc69d9', '02dd7371-03ef-5a43-ba96-1206a7c43f98', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-04-06', '17:30:00', null, '通常 / アイスを食べに続き', '（アイスを食べに2）レッスンの画像を見ながら集中して取り組めていました。今日は角度について取り上げました。左、下に動かすときの角度について少し困っていたので、角度の考え方についてはっきり説明しました。さらに壁に当たると初期位置に戻るアレンジをしました。アイスに触れたときと同様「もし」と「～に触れたら」を使ってプログラムすることに気づきがあったようです。 （アイスを食べに1）2は終わったのですが、1が終わっていなかったので戻りました。あるくんが話す言葉にアレンジを加えていました。', '2はしっかりできたので、アイスを食べにはもう終わっても良いかなと感じました。', 'タイピング: 評価Sでした！すごい！！
盛り上がり: とくに前半は楽しく取り組めました！！'),
  ('fa4d0a92-3713-5ed4-9731-7f1035e3aa4a', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-04-04', '17:30:00', null, '通常 / アイデア大賞初級続き', '前回の確認をした後、魚の動きをプログラムしていました。クローンの知識が浅く正しく使えていなかったので少しアドバイスをしました。新しいスプライトを追加するときにも見た目に気を付けて工夫してくれていました。音にもかなりこだわりがあるようです。 自分でどんどん進めていきますが、うまくいっていない部分も自分で考えたい様子です。自分で考えて進めいたいタイプのようです。どうしても詰まったときには声をかけてくれました。声掛けのタイミングが難しいです。', null, 'タイピング: 集中して取り組めていました。
盛り上がり: 音の調整にとくに力をいれていました！！楽しそうでした！'),
  ('5f34f8d6-ad6b-5f18-af87-ccff080539cf', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-04-04', '17:30:00', null, '通常 / アイデア大賞に挑戦（あと2回）', 'オリジナルの作品はもとのコードを確認しつつ、すぐに完成させることが出来ました。アレンジにも、とても積極的に取り組むことができました。箒を加えたり、背景を変えたりしました。スプライトが出てくる場所にもこだわって、座標をつかいこなすことができていました。来週続きをする予定です。', null, 'タイピング: 集中して取り組めました。
盛り上がり: 検定の 合格証をもらえて嬉しそうな様子でした。持って帰りそびれていたので来週また渡します。'),
  ('ff81e9bc-c1a6-5b26-ac49-df25ef1cac8a', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-04-04', '16:30:00', null, '通常 / アイデア大賞初級続き おわりの画面の作成を提案してみる', '終わりの画面を作成していました。丁寧にタイプして作り、表示させました。自分でコードを確認してゲーム終わりのタイミングを探すことができました。背景の変化とスプライトの表示に悩んでいたので、メッセージを使うことを提案しました。 ハートにある文字を変更してオリジナリティを出したり、コメントにアピールポイントを書いたりして工夫しました。最後に作品を公開できました。', null, 'タイピング: とても集中して取り組めていました。正解率100%！
盛り上がり: タイトルにオリジナリティがあります！半角にこだわっていました！！'),
  ('d2b4a0d1-9abf-5f93-929c-25e689c3aff0', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-04-03', '16:30:00', null, '通常 / アレンジ大賞 中上級', '今日はまだ中上級の中の全てのコードが写し終わっておらず、アイテムの部分を中心にコードを追加していました。 この部分がどうやら難しかった様子で、写すことにとても集中して行っていました。 今週来週とまだげんきくんの場合は時間があるので、一旦今週の金曜までに写し終わるを目標にして、来週の時に少し自分でアレンジを加えられたらいいのかなと思います。', null, 'タイピング: なし
盛り上がり: 自分で何回もコードの動作確認をし、ゲームを作成。一つのブロックが長いため終了時間になっても、しばらく続けていました（20時前には帰らせました） 今はコードを写すことで精一杯の様子ではありますが、一旦集中すると中途半端になってしまうのが嫌だったようで、1時間まるっとプログラミングをしていました。'),
  ('b1e64716-635f-5151-96ec-ce8bc41dfa57', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-04-03', '16:30:00', null, '振替 / アレンジ大賞 むらっち', 'むらっち以外の人をクリックしてしまうと一点減点というゲームに変更。 また最初のバグのような部分もいくつかヒントを出しながら、自力で導き出してくれたので、ゲームとしては完成となりました。 残り時間は、マリオゲームの方を写し、どいいうコードを書いているのか？をみながら作成。コードを写すこと自体は苦ではない様子でとても集中して最後まで行っていました。', null, 'タイピング: なんと、2ヶ月前のうでだめしよりも３レベルもアップ！小学校2年生ではとてもすばらしい！
盛り上がり: ゲーム性として他人にわかりやすくするという点をこだわっていました。むらっちとは違う人を色で変化させたりし、とっても面白くしてくれていたように思います！'),
  ('42e7544d-702a-5d37-a713-6a69727f96d9', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-04-03', '17:30:00', null, '通常 / アレンジ大賞の作成', '春休みもあって授業前も遊び、授業が始まる時にはすごき眠たそうでした。前回作ったところが一部保存されてなくて、作り直すことにすごく落ち込んでいたが、何とか進ませました。とちゅう、転寝しがちになり、別のコードを持ってきてしまう不注意なことがありました。その後、ブロックの塊ごとに終えたら見直しすることがさせてやったので、最後にバグが残らず、きれいに作り上げることができました。ただ、それで時間が来てしまったので、アレンジをする時間はありませんでした。', null, 'タイピング: 上位36%といいスコアが出ました
盛り上がり: 奇麗に一巡で作り上げてので、完成の喜びはとてもよかったです'),
  ('c485ccbf-def4-5f15-8c92-bddc8b186dc5', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-04-03', '16:30:00', null, '通常 / アレンジ大賞 初級 むらっち', 'むらっちを虫に変更、虫を倒すというものに変えていました。 ここまではコスチュームの変化なので、実際のコードを変化させているのではないため、スコアを作って、点数が一定の条件になったら、何かしらのアクションを追加してみてはと提案。 点数が色々な点数になった際に出てくるメッセージを追加して、アレンジしていました。 来週は、おそらく完成に進むと思います。', null, 'タイピング: かつてのスコアよりもかなり伸びていて、以前はブラインドタッチもままならなかったのがとても成長したように思います！
盛り上がり: 色々な条件分岐を増やしてくれ、自分でもその条件をどのタイミングで出したらいいか？と考える力を発揮してくれていたように思います'),
  ('6154f172-7ff6-5614-8713-2cf6e3961140', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-04-03', '16:30:00', null, '振替 / アレンジ大賞の作成', 'ルイージのモグラに対してのダメージ判定がなかったり、ジャンプが1回しかできないバグを直していきました。途中いろいろといじりすぎてバグがなかったマリオにもバグが発生したので、リストアして探し直しました。それでもなかなか自力では見つけづらかったので、助言しました。そして、原因として上の「もし」の条件にかぶっていたり、変数名違いの不注意によるものでした。 モグラがあまりにも多く発生するので、モグラを殴るのアクションで消すようなアレンジを作り始めました。コスチューム番号の範囲で条件を指定して作ろうとはしていましたが、条件以外のときも消えてしまうことがあってうまくいきませんでした。そこのところ、次回で完成を行けたらいいと思う。', null, 'タイピング: 日本語1文字ずつ打つ間隔が短くなってきました'),
  ('1179accc-1e1c-5cd3-8ccd-39de1d246010', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-04-03', '17:30:00', null, '振替 / アレンジ大賞 初級のアレンジ', 'コスチュームなど変化させた部分までは自力でできました。 今度は以下の条件を追加したいとのことで、一緒に考えていました。 ①条件１タイム30秒のうちに、スコアが30にならなければ、ゲームオーバー ②タイム30のうちにスコアが30になったらクリア 変数を作って、ゲームオーバーとクリアをつくったまでは良かったのですが、①と②の条件分岐が意外に難しく、最後の時間内では終わらなかった→今週10日の土曜日に一緒に考えてもらえると助かります。', '変数を作って、ゲームオーバーとクリアをつくったまでは良かったのですが、①と②の条件分岐が意外に難しく、最後の時間内では終わらなかった→今週10日の土曜日に一緒に考えてもらえると助かります。', 'タイピング: 簡単レベルを選んで、なんとノーミス！とっても嬉しそうにしていました！
盛り上がり: 自分で考える力→こうしたいという意欲はとても素晴らしい。ちょっと今日は久しぶりだったのもあってうる覚えなところもありましたが、そっか、こういうことか！という理解につながっていたようで、良かったです。'),
  ('ebffd43c-6d57-54d3-a6fa-debb1e3453c1', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, null, '2023-03-28', '17:30:00', null, '休み（振替対象）', null, null, null),
  ('1e117efb-adea-55c6-ad0f-bb1127d9148c', 'cf94ca77-6621-5a19-b35e-6f2e124107d6', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-03-28', '17:30:00', null, '通常 / Scratchを楽しむ', 'カウンター席で、飴を傍らに、熱心にパソコンに向かっていました。 最初はScratchのゲームで適当に遊んでいましたが、途中からアルスパークを開いてオリジナルのコスチューム編集を熱心にやっていました。Scratchのネコの色を変えて帽子を描き加え、マリオのようにしてバッタと追いかけっこをしながらぐるぐる動く作品を作ったので褒めたところ、その後5体くらい、新しいオリジナルスプライトを描いて動かしていました。', null, '盛り上がり: コスチューム編集画面でのお絵描きを熱心にやっていました。 Scratchでは、マイクラアスレチック系のゲームを開いて遊んでいました。'),
  ('6077ee97-1d29-59e6-856a-89e4db0e6906', '5c9bb4b1-2f4b-5e1e-9f34-bcc4d0dea21a', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-03-28', '17:30:00', null, '通常 / アレンジ大賞の作成', '家でScratchで作成していたゲームがあるそうで、その仕様を活かしたいと思い出しながらアレンジをしていました。かなりオリジナリティの強い作品になりそうです。 条件分岐よりもメッセージを多用する方が好みのようです。一つのメッセージをきっかけにいくつかのコードが動くようにしていたため、メッセージの発信と受信の関係をきちんと整理することを勧めました。 隔週コースのため、自宅での作業もできることを提案しましたが、ゆずとくんなりにシミュレーションして、あと1回の授業時間内で完成できるとのことで、IDのお知らせはしませんでした。', null, '盛り上がり: かなり早く来室したため、ほぼ2時間かけて熱心にアレンジをしていました。 ゲームの遊び方の仕様を変えてみたかったらしく、オリジナルのボタンを作成して満足そうにしていました。'),
  ('b9343c23-e2e3-5f44-8d99-69aa7e1be397', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-03-28', '16:30:00', null, '振替 / アレンジ大賞作品の作成', 'スタート画面をこだわりをもって丁寧に編集していました。 ゲーム終了の画面を、メッセージを使ってきちんと作成することができていました。 絵やデザインに好みがあり、じっくりと編集したがる傾向がありますが、コードの方も促せば丁寧に読み取ることができました。 一人でどんどん先に進むというよりは、一つ完成すると先生に見てほしそうにして待っていて、声をかけると嬉しそうに解説をしてくれる、という感じです。', null, '盛り上がり: デザインの変更が満足できるところまでできたようで、嬉しそうにしていました。'),
  ('70cf1ff9-12f3-5dde-a50a-8b1f7f26f539', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-03-28', '17:30:00', null, '通常 / アレンジ大賞に挑戦', 'まずは元作品を見ながらプログラムを作ってもらいました。作りながら音の追加などの工夫をしていました。アイデアが尽きてしまったようなので、終わりの画面の設定を提案しました。その後、新たに魚などを追加して新しいステージを作っていました。魚を動かしたい方法があるようですが、時間の都合で最後まで終わりませんでした、次回挑戦です。', '魚を動かします。', 'タイピング: 学校でもやっているそうです。途中で疲れてしまったのか、適当に打ってしまっていることがありました。
盛り上がり: アレンジのアイデアが徐々に出てきました。'),
  ('73ce41e7-104a-5d9c-8b7c-9d4c4acb99a4', '7d01236e-620e-5177-a6f4-af325a582aae', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-03-28', '17:30:00', null, '通常 / アレンジ大賞に挑戦', '一通り遊んでもらいました。初級に取り組むことになりました。元の作品を見ながらまずはゲームを作ってもらいました。丁寧に取り組めていたので良かったです。アレンジとして音にこだわっていました。BGMとして設定した音を最後に止めるのにかなり苦戦している様子でした。プログラム時に背景を変化させることが必須なので、まずは自分で選んでもらいました。次回は背景選び＆音止めに挑戦する予定です。', 'BGMの音を止める', 'タイピング: とても集中して取り組んでいました！
盛り上がり: 音にこだわりがある様子でした！'),
  ('2d6f3fa4-8212-5398-8d27-44972ad8ae1a', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-03-28', '16:30:00', null, '通常 / アレンジ大賞初級に挑戦', 'もとのプログラムを見ながら作品を作りました。春休み中だからか、普段よりも集中力が低いように感じました。元の作品と同じようにプログラムし、終わりの画面の作成、出現をしました。 本人曰く、アレンジはあまり好きではないようです。アイデアもたくさん思い浮かぶようではないそうなので、こちらがアイデアを提供する必要があるかもしれません。', null, 'タイピング: 集中して取り組めていました。得点もかなり高かったです。
盛り上がり: マイクラの文字を何も見ずにタイプできるようになったそうです！報告してくれました。'),
  ('8725e0a9-735d-5f62-a8dc-8d8bd848d9ed', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-03-28', '16:30:00', null, '通常 / アレンジ大賞の作成', 'コスチュームの編集によるむらっちの動きはすぐに理解して、楽しそうにスプライトを変更して編集していました。 完成品を見ながらのコードの読み取りに関する質問には答えられるのですが（このコードはどの動き？や、出てくるむらっちの数を変えるには？など）、実際に編集を始めると、どこを変更すればいいんだっけ？という質問が何度かありました。読むことは慣れてきているようですが、書く方にはまだ不安があるのか、こちらに確認してからやりたがる傾向がありました。', null, '盛り上がり: コスチュームの編集にはさすがに慣れていて、仕様の理解も早かったです。 スタート画面の文章にもこだわって、楽しそうに取りかかっていました。'),
  ('ff0f4aea-b036-538c-bd6d-3525e145d72c', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-03-24', '16:30:00', null, '通常 / アレンジ大賞の作成', 'ゲームのアレンジは色々と思いつくようで、積極的に考えたアレンジを作成して試していました。 ゲームをクリアしたら、上からコインが回りながらおりてくるコードを作成していて、回るのと上から動くのが同時にできないと悩んでいたので、順次処理の説明をしました。ブロックは必ず上から順に実行するため、同じタイミングで実行させる手段を考えさせ、コードを並列で作成することに行きつくことができました。 ボーナスタイムの作成などは、自分がこれまで習ったブロックをうまく使用してできていました。', null, 'タイピング: 正誤率が上がってきていて、本人もこの数値を励みにしているようでした。
盛り上がり: とても楽しそうにアレンジをしていました。自分が考えたアレンジが形になるのがとにかくうれしそうで、いつもより口数も多く、何をしたいかという要望や質問も、通常より積極的にしてくれました。 アレンジを通して、複数のコードを作成すること、「止める」ブロックの3つの種類の違い、複数のメッセージの使い分けなどの理解が深まったようでした。'),
  ('123d3091-745a-5dbd-882f-ed06ebc358b5', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-03-24', '16:30:00', null, '通常 / アレンジ大賞の作成', '初めに見本のコードを完全に写経してからアレンジに入る、と言って、前回から1時間少しかけて、写経をしていました。虎くん曰く、「きちんとコードを見ながら写した」そうで、その後の編集などもすぐに該当箇所を見つけることができていて、「ちゃんと中身を見てたからね！」と得意そうでした。 昨年のコンテストで作成したモグラやキツネなどのキャラクターを取り入れて、アレンジを加えていました。こちらも何度も使っているため、どのコードでどのような動きをさせているのかがよくわかっていて、一緒に作成していた大空翔くんに、得意そうに説明したり、アレンジの成果を二人で試したりと、とても盛り上がっていました。', '備考有り', 'タイピング: タイピングは面倒だからと飛ばすことも多いのですが、プログラミング検定の合格証を渡して、タイピングに続いていい結果が出たね、と声掛けをしたら、「1回だけ練習してみようかな」と言いつつ3回ほど真剣に取り組んでいました。
盛り上がり: タイピングもアレンジも、今回は途中で投げることなく授業が終わるまでとても集中して取り組めていました。 自分のアレンジを大空翔くんや、時にたっちゃんが熱心に聞いてくれるのが、とても嬉しそうで、よりウケるアレンジをしようと一生懸命な様子が見られました。
備考: 家では検定があまりできなかったと話していたらしく、合格の証書を親子でとても喜んでいました。次の級にも興味があるそうですが、中学受験のため1～3月は難しそうとのこと…。でも、せっかく頑張ってきたプログラミングが内申のアピールポイントになるなら、次の級もチャレンジしたいというのが、本人とお母さんのご意向のようです。'),
  ('16d6dc1a-e21e-56f9-9ae6-59acc6eced82', '7ac1ed6d-2eb1-56f7-aa62-e5d1ce95a957', null, '70028bf6-d858-5232-8ea5-b8b16ca0503f', '2023-03-23', '17:30:00', null, '通常 / 演算式を活用したスプライトの色々な動きを学ぶ', '"スプライトが画面端に近づくにつれて動きの速さを変える、スプライトの大きさの変化のスピードを少しずつ変える、ボールがバウンドするような動き、三角関数を利用した波状の動きやばねのような動きなどの説明を受け、自分でも作成していました。 澤本先生の問いかけにもよく反応してくれていました。', null, '盛り上がり: もともとジャンプの動きを作るのが好きなせいか、「これ、俺がいつもやってるやつ！」などと嬉しそうに反応していました。'),
  ('3262111e-2c88-5f1d-831a-4bff8f471f0a', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '70028bf6-d858-5232-8ea5-b8b16ca0503f', '2023-03-23', '17:30:00', null, '通常 / 演算式を活用したスプライトの色々な動きを学ぶ', '"""スプライトが画面端に近づくにつれて動きの速さを変える、スプライトの大きさの変化のスピードを少しずつ変える、ボールがバウンドするような動き、三角関数を利用した波状の動きやばねのような動きなどの説明を受け、自分でも作成していました。 少し難しそうではありましたが、承太郎君と話しながら、最後まで頑張っていました。', null, 'タイピング: 相変わらずスピードはかなり速いです。
盛り上がり: スプライトがバウンドする動きの作成のところで、最初はめり込んでしまったのを面白がり、澤本先生の指示通りにして修正できたときは承太郎君に声をかけ、楽しそうにしていました。'),
  ('bf2f29d7-605d-54f0-a7a7-8dae1013def1', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '70028bf6-d858-5232-8ea5-b8b16ca0503f', '2023-03-23', '17:30:00', null, '演算式を活用したスプライトの色々な動きを学ぶ', '"スプライトが画面端に近づくにつれて動きの速さを変える、スプライトの大きさの変化のスピードを少しずつ変える、ボールがバウンドするような動き、三角関数を利用した波状の動きやばねのような動きなどの説明を受け、自分でも作成していました。 作成していた画面から、それなりに理解はできたいた模様です。', null, '盛り上がり: 特に悩むこともなく、スラスラと作成ができていました。'),
  ('4a6d8323-090e-5745-b9e5-b9c1478794c7', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-03-24', '16:30:00', null, '通常 / 初級アレンジ続き', '前回の続きに取り組みました。説明文をスタートボタンを押したときに何秒間か表示されるように工夫していました。「よーいドン」の表示もスムーズにいくように「〇秒まつ」を効率的に使うことができました。やりたいことは自分の言葉で説明することができていて良かったです。次回は、終わりの画面の出現に取り組みたいそうです。', null, 'タイピング: 集中して取り組むことが出来ていました！正誤率も100%でした！！
盛り上がり: とらくんの作品も気になりながら取り組んでいました。'),
  ('7ded00ca-3b36-5b8c-8093-3bc5571c9418', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-03-24', '17:30:00', null, '通常 / アレンジ大賞初級に挑戦', '最初に元のプログラムを見ながら、作品を作りました。次にアレンジに挑戦してもらいました。「アレンジ」という言葉にあまりなじみがなかったようです。具体例を私の作品で遊んで確認してもらいました。スコアが25点のときに、おわりの画面を表示するようにしました。むらっちの出る回数、クリックする回数が25点に満たないとうまくプログラムを終えることができないので、次週は終わりの条件の見直し、むらっちの出現回数の調整をするといいかなと思います。', null, '盛り上がり: アレンジ大賞の景品にとても興味ある様子でした。今日も1時間一杯取り組むことができていたので素晴らしかったです！'),
  ('a84b812c-0f0f-5fd0-92b2-0ccdafcd64f4', '90dcd5c1-f4a7-5da5-8623-220cd9cb625b', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-03-24', '18:40:00', null, '通常 / オリジナル作品の作成続き', '先週作っているゲームの広告ゲームの部分を作りました。アイデアが思い浮かばなかったようなので、私が作った作品を参考にしつつ、自分で新しいものを作っていました。「広告」というところに注目して作品を作ることができていました。キャッチゲームのような作りのものでしたが、広告から本編に戻るときに面白さがあってとても良かったです。', null, 'タイピング: とても集中して取り組むことができていました！スコアもかなり高かったです。
盛り上がり: とても楽しく取り組めました！'),
  ('0b53c385-9ea9-5523-87ba-8a09665111d7', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, null, '2023-03-24', '18:40:00', null, '休み（未対象）', null, null, null),
  ('8f06e66a-3db5-5789-8af6-fca8704281e0', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, null, '2023-03-24', '17:30:00', null, '休み（未対象）', null, null, null),
  ('10bd1cc0-d111-5f36-b06b-e1491adb6a6f', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, null, '2023-03-24', '16:30:00', null, '休み（未対象）', null, null, null),
  ('13f03cfb-6469-5312-97d7-37a69a302349', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '70028bf6-d858-5232-8ea5-b8b16ca0503f', '2023-03-23', '17:30:00', null, '通常 / 演算式を活用したスプライトの色々な動きを学ぶ', 'スプライトが画面端に近づくにつれて動きの速さを変える、スプライトの大きさの変化のスピードを少しずつ変える、ボールがバウンドするような動き、三角関数を利用した波状の動きやばねのような動きなどの説明を受け、自分でも作成していました。 なんとなくではありますが、理解はできたとのこと。', null, '盛り上がり: 説明を受けながら、他のPVのコードと照らし合わせて確認したりして、知識を吸収しようとする姿勢を見せていました。 最後のバウンドなどは、面白そうに取り組んでいました。'),
  ('76e94863-aaab-5834-a457-8f83106e6ea4', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-03-23', '16:30:00', null, '通常 / アレンジ大賞の作成', 'アレンジ大賞の作品を作っていきました。教室に来て浅いながらもアイデアは止まらずに作り続けていました。むらっちの色を変えて、その色の雰囲気に合わせて、音楽や背景を変えて作れていました。ただ、イメージをあるので、途中コードで困っていたのを助けていきました。そして、ダミーもつくり、それを押したらゲームオーバーになる仕組みで面白くなっていました。', null, 'タイピング: すくすくと進めていました
盛り上がり: 手を止まらずに作って楽しそうにやっていました。'),
  ('deefd34e-29cc-5e90-92cb-33505552e794', 'b2246586-4496-52f9-a825-be2488a00a31', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-03-23', '17:30:00', null, '通常 / アレンジ大賞', '最初はいつものように自由作品を作っていたのですが、先週のマリオの続きをやろうと促すとやってくれました。まずは前回作った左右移動、ジャンプと同じ要領でパンチの動きを作りました。攻撃中かどうかを示す変数を使い、パンチしたときにHPを減らすのもできました。そして、HPが0になった時に不等式で判定して"1P(2P) WIN"の文字を表示しました。最後の方に、製作には至りませんでしたがアレンジのアイデアを話してくれました。虹色に光って大きなダメージを与える「スペシャルパンチ」を考えているそうです。', null, '盛り上がり: 作ったゲームで先生と対戦するのがすごく楽しそうでした'),
  ('c8ec407d-88c5-5077-8727-16ac203c6c3c', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-03-18', null, null, '通常 / アレンジ大賞作品の作成', 'ゆうかちゃんと一緒にアレンジ大賞の説明とゲームの説明をしているときは、ゆうかちゃんの反応がはやいせいか、うなずく程度でしたが、個人作成になって席をわけると発言ができるようになりました。 ゲームを可愛らしい雰囲気にしたいようで、選んだスプライトの編集などを工夫して熱心に作成していました。', null, '時間帯: その他
タイピング: 丁寧にできています
盛り上がり: 一人で作成を始めたら、発言や質問も増えて楽しそうに作成していました。'),
  ('e08ead57-79ba-537e-aaa8-211597db2dda', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-03-23', '16:30:00', null, '通常 / アレンジ大賞の作成', '前回に続いて中上級のアレンジ大賞の作品を作っていきました。基本は自分で考えながら作っていきました、アレンジでは第3勢力のすらぼーを作って、ランダムな動きで戦闘をかく乱するようになっていてとても面白くなっていました。', null, 'タイピング: 安定感が出ている'),
  ('6acdfc28-c697-5382-a4f7-c1f391b02a09', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-03-23', '16:30:00', null, '通常 / アレンジ大賞', 'むらっちたたきで遊んだあと作り始めました。写経してもいいと伝えましたが、できるところまで自力で作ることを選びました。オープニング画面を消してゲームスタートするところはできました。また、アレンジとしてはむらっちの頭の色にグラデーションをつけたり、背景を変えたりしていました。肝心のゲーム本体がまだ作れていないので、最後の方は本体の制作に移ろうと促しました。', null, 'タイピング: 英単語を頑張っていました！普段使わないキーがあったからか難しかったそうです
盛り上がり: アレンジを楽しんでいました。'),
  ('a610f311-6aa3-5f6d-ab43-54a5c0f324ab', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, null, '2023-03-17', '16:30:00', null, '休み（振替対象） / ⇒4/25（火）17:30～に振替え', null, null, null),
  ('45806518-35d0-518d-9b9e-c5918cccc836', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-03-20', '18:40:00', null, '通常 / アレンジ大賞続き', '前回の確認から始めていました。見本と見比べやすいようにパソコンをもう一台作りましたが、タブを移動して見比べるほうが快適な様子でした。とても集中して取り組めていました。体の上部と下部が別で動いてしまう事故が起きました。本人も怪しそうな箇所をピックアップして、原因を探していました。今まで作ったプログラムをよく確認する良い機会になりました。ブロックを外しながら原因を探す方法についても少し共有しました。理由はタイマーが怪しそうだという結論になりました。とても集中して取り組めていました！', null, null),
  ('eb2857d5-8184-5fc9-b72f-23b16a3dcb8d', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-03-20', '16:30:00', null, '通常 / アレンジ大賞', 'クローンは使ったことがなかったそうですが、クローンは分身だという話などをすると理解して写経しました。アレンジに関してはほうきでクモを追い払うものにすると決めて取り掛かりました。途中、スコアが加算されなくなるバグが起きましたが、クローンと本体の動きを混同していることが原因だと分かりました。「クローンされたとき」ブロックの使い方を説明すると修正できました。', null, '盛り上がり: やりたいアレンジの方向性がすぐ決まっていてすごいと思いました。'),
  ('1821566a-4fa8-516f-951a-69c1658ffbbd', '51e2226d-51fc-52c1-afb9-84ab378d517c', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-03-20', '18:40:00', null, '通常 / 自由作品（最後の授業のため）', 'アレンジも大会を1時間でやりきるか、自分で自由作品を作るかを選んでもらい、自分で作品を作ってみるということになりました。 サッカーゲームを作ろうとしていた様子で、スピードが早くなるメーターや変数を組もうとしていました。参考にしていたのが過去問の２級問題。実際にやっていた問題を覚えていたのはとても素晴らしい！ ただスプライト同士のリレーションが関係して全てを完成するまでとは行きませんでした。 ただ、自分でやりたいものを決めてちゃんと作成しようとしたのは、良かったと思います。', null, 'タイピング: なし'),
  ('2efbe288-d186-5efc-bd0f-525a605c0d8f', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-03-20', '17:30:00', null, '通常 / アレンジ大賞に挑戦', '初級、中級の両方を遊んでもらいましたが、本人の希望で中級に取り組むことになりました。最初に「面倒くさい」と言っていましたが、いざ始めるとしっかり集中して取り組むことができました！「～回繰り返す」と「～まで待つ」を見間違えてうまくマリオが動いていませんでした。本人がプログラム的に怪しい箇所を探すことはできていました。見直しても間違いに気づくことができなかったので、注意力をもっと上げていきたいです。', null, 'タイピング: 集中して取り組めていました！！'),
  ('eaed0cab-cffa-5655-9670-e80cdecb672e', 'ec5baeb0-d065-53b9-a675-d99033f1812e', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-03-20', '16:30:00', null, '通常 / アレンジ大会 初級', '自分で変数を組み、むらっちが変数でさらに増えていくというコードを書きたかった様子、 ただクローンの動作自体が癖があるため、コードの組み立てとメッセージの送り合いに四苦八苦していました。 完成までとは行きませんでしたが、色々と自分で考えて組み立てようとしていたのは素晴らしい点だったなと思います。', null, 'タイピング: なし
盛り上がり: 最後の授業となったため今日は自分の発想を思う存分発揮してもらいました。 何かが完全にできなくても、ヒントがあれば「あぁそうか」と自分なりに理解できるということはとても素晴らしい能力の一つだと思います。'),
  ('7510bcd7-cdd6-5b9a-afb5-7d5653061b60', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-03-20', '16:30:00', null, '振替 / アレンジ大賞初級つづき', '前回の続きをしました。本格的にアレンジを進めていました！「スコアが40点以上になったら」の表現方法について共有しました。≧、≦をよく知らなかったようですが、説明後スムーズに使うことができていました。特定の点数になったらスプライトを消したいとのことだったので、「このスプライトの他のスクリプトを止める」というブロックの意味について紹介しました。スプライトに工夫を加え、とても面白い作品が作れています！', null, null),
  ('9f67df2f-2b65-5298-b6a7-e0e48101ca68', '9fa414fa-958c-54ca-a3e6-d0d8dc0eae6b', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-03-20', '16:30:00', null, '振替 / アレンジ大賞総選挙', '中級も気になるようですが、自分の出来る範囲でうまく作るということで初級に挑戦することにしました。今日はいつもと違う環境からかあまり集中もできず、気がかなり散っていました。ほぼブロックを書かずに「バグだ」と言っていたのが、残念でした。むらっちが出現する、クローンを使ったプログラムは完成させることが出来ました！次回はプログラムを完成させ、アレンジに入っていきたいです。', null, null),
  ('340aaf04-f8a9-53df-946e-ebb1976a12b7', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-03-20', '17:30:00', null, '通常 / アレンジ大賞', '自分でできるところはやって、できないところは完成版のコードを見ながら作るという形で進めました。ジャンプがよくわからないということだったので、座標の復習を軽くしたあとその部分を写経しました。移動やパンチ、キックは自力でできました。アレンジではルイージをオートで動くようにしたいと言っていたのですが、完成版と同じところを先に作り終わってからそっちに移ろうと促しました。', null, 'タイピング: きょうはココアタイピングとplaygramを両方準備していたのですが、珍しくplaygramをやってみていました。
盛り上がり: 賞は絶対取れないと言っていましたが、中上級のゲームでなくてもここから頑張れば可能性は出てくると元気づけました。'),
  ('08d93a7a-4ce0-50e9-800f-67de3d9e72ec', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-03-18', null, null, '通常 / アレンジ大賞作品の作成', 'アレンジ大賞の説明のときから、興味深そうに聴いてくれていました。クローンなど未履修のコードがあるため、なつめちゃんと一緒にゲームのコードの解説を聞いてもらいましたが、こちらの問いかけにも積極的に答えていて、コードを読み解くこともよくできていました。 むらっちのスプライトをガチャに変えたり、背景の色をグラデーションを使ってファンシーにしたりと、ゆうかちゃんらしい可愛いアレンジをしていました。 デザイン面では個性が出せたので、次回以降はコードの方でアレンジをしていこうと声掛けをしました。', 'コード面でのアレンジをしてもらいたいです。', '時間帯: その他
タイピング: 安定して高スコアを出せています。
盛り上がり: アレンジは好きそうで、終始楽しそうにやっていました。 色使いなど、ゆうかちゃん独自のアレンジセンスがよくできていて、声掛けをしたら嬉しそうに説明をしてくれました。'),
  ('5daa4183-5ad6-59f3-8d47-c74a7c2de699', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-03-18', null, null, '通常 / アレンジ大賞', '約束の時間までゲームをさせ、そのあとむらっちたたきのコードの写経をやってもらいました。今日はいつにも増して気が散ることが多かったのですが、ゲームの初期設定はできました。最後にみんなで今日の作品の見せ合いをしたのですが、そこではやりたいアレンジを話すことができていました。 パソコンやマウスを雑に扱って遊んでいたので、それは壊れちゃうからダメだよと伝えました。', null, '時間帯: その他'),
  ('0f9395f2-f85d-5565-b77c-48048cba8f7f', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-03-18', null, null, '通常 / アレンジ大賞', 'アレンジ大賞について説明すると、だいきくんはマリオのゲームを選びました。このゲームはすでにスクラッチで遊んだことがあるらしく、コードを見ると内容をほとんど理解したと言っていました。そのためコードをコピペすることで完全版の再現が終えました。そのあとは、HPが0になってもゲームが終了しないバグを直したり、音を追加したりという作業に入りました。デバッグができているので、コードの全体像や意味を把握することはできていると思います。', null, '時間帯: その他
盛り上がり: アレンジ大賞の賞品のことを説明しましたが興味がないようで、アレンジ自体をやりたい気持ちが強そうです。'),
  ('a92e5c6b-4dc2-5c68-9b17-f0cc0e40fcd6', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '25840600-1a86-5fb0-b223-dec47cec8c48', '2023-03-18', null, null, '通常 / アレンジ大賞総選挙', '最初から最後まで集中して、作品を作ることができました。', '初級課題が完成したので次回はアレンジ。 できれば 「どういうアレンジをするか決める→どれぐらいの時間で作るか決める→やってみる」 という手順でやったほうがいいと思います。', '時間帯: その他
タイピング: しませんでした
盛り上がり: 写経でしたが、途中でむらっちが出てくるところで画像を削っったり配置を調整したりするところではよく考えてできました。 課題の完成まで一生懸命取り組んでいました。
備考: 今日は以下のことを実行したため、最後まで集中して授業に取り組むことができました。 次回からの参考にしてください。 １、集中できない要素を取り除く 不要なタブ(ゲームなど)を消す、話を聞いているときにPCを操作させないことを徹底。 本人はわかっているので、ちゃんと注意すれば強く言わなくても大丈夫です。 ２、「もうちょっとまって」などの甘えに取り合わない 授業とは関係ないことや、今すべきでないことをしているときは、すぐにやめさせる。 本人もやるべきことはわかっているので大丈夫です。 ３、次のプロセスを守る 「何をやるか決める」→「どのくらいの時間でやるか決める」→「終わったら褒める」 ※時間設定は余裕を持った時間になるよう誘導。 ※集中が切れそうなときは残り時間を教えてあげる。 ※関係ないことをやっていたらすぐにやめさせる。関係ないことをやってるにもかかわらず「じゃあ〇〇が終わったらね」などとしてしまうと、集中できなくなってしまう。 ※「何をやるか決める」の部分は本人任せで、間延びしてしまうと集中が途切れる原因になりかねないので、対応には注意 授業後も家でアルスパークを使ってアレンジしたいと言っていたりと 集中して授業に取り組むことは、本人の充実感にもつながるので、次回もうまく集中して授業に取り組めるようにフォローをお願いいたします。'),
  ('8005abc7-e935-5c51-ab31-9e01276196af', '80660755-d846-5cdd-91a4-0ab78fe29034', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-03-17', '18:40:00', null, '通常 / アレンジ大賞作品の作成', 'アレンジ大賞の説明をしたとたんに、「アレンジしていいの？！」と食いついてきました。 むらっちのスプライトをすぐに戦闘機に変えて、熱心に元のコードを見ながら写していました。 コスチュームで図を回転させたり絵を足したりと、デザイン面、プログラム面の両方から頑張ってアレンジをしていました。', null, 'タイピング: 今日はすぐにプログラミングをやりたいとのことで、飛ばしました
盛り上がり: アイディアがどんどんわいてきて、お迎えがきてもしばらく止まらずに作成を続けていました。 戦闘機のパイロットを足したりセリフを足したりと、最後まで集中してアレンジをしていました。'),
  ('3ce42fb0-1658-5050-8798-5ae900108585', '90dcd5c1-f4a7-5da5-8623-220cd9cb625b', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-03-17', '18:40:00', null, '通常 / 自分の作品作成続き', 'リストのゲームはとりあえず完成した様子。ただ間違えたらゲームにするというのは、なかなかメッセージを送るのが難しかったようで、新たにゲームを作成していいか？と聞かれたため最後だしと思い、ひとまず自分なりに作品として作れるものを作成してもらいました。 まだ作品の途中なので来週どうなるか？は分かりませんができるところまでやってもらえたらそれでいいかなと思います。', null, '盛り上がり: １級が受かって嬉しそうでした。'),
  ('6bbe107c-9569-555b-b09b-200b7d1d3e65', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-03-17', '18:40:00', null, '通常 / アレンジ大賞に挑戦', '全てのプログラムを遊んでから選んでもらいました。1時間とても集中して取り組むことができていました。ひとつのスプライトではなく、いろいろなスプライトのプログラムを少しずつ進めていました。うまくプログラムが動かないことがあったようですが、メッセージと変数の名前が間違えやすいことを共有して、よく確認してもらいました。次回も続きをします！！', null, null),
  ('42585e04-e0d5-51c2-b213-0a7688f7a38f', '13bd73d0-f535-5291-8362-6712e5cd7384', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-03-17', '16:30:00', null, '通常 / アレンジ大賞作品の作成', '持参したPCのレスポンスが悪く、途中で教室のPCに替えました。 数回遊んだ後は、自力でアレンジしながら作ってみたいと言って、考えながら頑張っていました。 お迎えの時間まで頑張って、ゲーム部分はほぼ完成できていました。', null, '盛り上がり: PCを替えてからは調子が良さそうで、熱心に進めていました。 ニコニコしながらちょっとスプラッタなアレンジをしていました。'),
  ('4387ce96-e7d9-5cd2-9bce-1daa81e2a02f', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-03-17', '17:30:00', null, '通常 / アレンジ大会用のゲーム マリオゲームをアレンジする', '今日はクラス前に友達と遊んできたらしくちょっとお疲れモード。集中力も欠いていて、どのコードを今自分が書いているのかが分からなくなっている様子でした。 隣にいて、「どのコードを書いているか？」を聞きながら、やっていました。 まだ来週もしばらく全体のコードを写すというのに時間がかかってしまいそうなので、ちょっとせっついてやらせた方がいいかなと', null, 'タイピング: なし'),
  ('e0292f15-76be-5f30-b914-24e04d8f8038', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-03-17', '16:30:00', null, '通常 / アレンジ大会用の中級ーマリオゲーム', '最初に難しい中上級でもOKだよと話したら、アレンジがしにくそうと本人が言ったので、結果マリゲームの方でアレンジ作品を作成することになりました。ひとまずコード全体を写してゲームを完成させるところから。 やっている間にわからなくならないように、それぞれのブロックの塊にコメントを追加して自分で後で理解しやすいようにしていました。ひとまず今日は全部写すので精一杯だったぽいので、来週は自分でアレンジするところからだと思います。', null, 'タイピング: 集中して行っていました！
盛り上がり: 自分でアレンジしやすい方を理解している、写している最中にどういうコードを書いているのかを真剣に読んでいました！'),
  ('e193032e-3cc7-54e2-852b-1e5ab72d6405', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-03-17', '16:30:00', null, '通常 / アレンジ大賞に挑戦！', 'ゲームの内容は自分でなんとなく考えられている様子でした。むらっちが出現するときの見た目がうまくいっていないようだったので、コスチュームについての考えを共有し、プログラムの間違っていそうな箇所を自分で探して確認していました。見本と同じようにプログラムした後、オリジナル要素として追加したゴールドむらっちが出現する間隔を調整していました。クローンの考え方を共有してから工夫してもらうと、表現の幅が広がるかなと思いました。', null, 'タイピング: 集中して丁寧に取り組めていました！！'),
  ('7cccf476-b3bd-524f-8432-ecbcd6248fd9', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-03-17', '16:30:00', null, '通常 / アレンジ大賞作品の作成', '1時間、離席もせずに集中して取り組んでいました。 むらっちの他にひっかけキャラを作って、得点がマイナスされるアレンジを作成していました。コードもよく読んでいて、必要なコードのみをむらっちのスプライトを見て写していました。 一つ目のアレンジがちょうど時間内に終わりました。', null, '盛り上がり: やりたいアレンジがすぐ思いついたようで、楽しそうにアレンジしていました。 思うように表示ができなかったときも、自分でコードを見直して修正できて、得意そうにしていました。'),
  ('c8d2ea5a-1416-5258-b0b0-f16d7b480e54', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-03-17', '16:30:00', null, '通常 / アレンジ大賞に挑戦', 'スプライトを変更してプログラムを始めていました。コスチュームの順番に注意して、うさぎの滑らかな動きをプログラムすることができていました。最後に、クリア条件を設定していました。もしの使い方で混乱していましたが、最後にはうまくクリア画面を出すことができていました。次週はレベルアップさせて次のステージをプログラムしたいそうです。', null, null),
  ('b457964d-751e-5554-9fb3-b9d8663e67fb', '02dd7371-03ef-5a43-ba96-1206a7c43f98', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-03-16', '17:30:00', null, '通常 / サメから逃げろの完成、応用', 'サメから逃げろについては、サメに食べられたら隠すのだけできていなかったので、「もし～に触れたなら」を教えて完成させました。また、かずまくんの希望で隠れると同時に音を鳴らしました。さらに、タイマーで逃げた時間を記録したいとも言ってタイマーをつけました。 そのあと、レッスンから「アイスを食べに1」を始めました。数字を入力するところで全角になっていたため、全角と半角の違い・切り替え方を伝えました。一番最初の座標だけ決められました。', 'アイスを食べに1続き', 'タイピング: 徐々に慣れてきています
盛り上がり: 話が脱線することがなくなったわけではないですが、題材となったゲームに興味をもっているのである程度集中できています。'),
  ('0c3fb4ba-6c9e-54a6-94da-879ada94d117', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-03-16', '17:30:00', null, '通常 / アレンジ大賞作品の作成', 'マリオのコスチュームを丁寧に見ては考え込んでいました。攻撃の種類を増やすアレンジをしてみたいとのことで、コスチュームと攻撃の関係などを調べていたようでした。 スタート画面のボタンなどを熱心に作成していました。', null, 'タイピング: 相変わらず猛スピードで熱中していました
盛り上がり: ゆきちゃんは、元になる作品がある方がイメージがわきやすいようで、楽しそうにアレンジを考えていました。'),
  ('97aac9a3-c2c1-578e-9ffd-2c408a78b7f4', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-03-16', '17:30:00', null, '通常 / アレンジ大賞作品の作成', '中級と中上級をじっくりプレイした後、自分なりのアレンジがしやすそうだからとマリオを選んでいました。 承太郎君なりのゲームの開始イメージがあるようで、スタート画面から作成をしていました。', null, 'タイピング: ゆきちゃんと結果を見せ合いながら、かなりの勢いでやっていました。前回の毎パソの反省からか、ミスタイプを減らそうとする努力が見受けられました。
盛り上がり: スタート画面の作り込みなどが得意分野のせいか、楽しそうにサクサクと作っていました。
備考: 検定の結果を口頭で伝えたところ、「あー、よかった～」とほっとしたようでした。'),
  ('12496826-b3af-57d2-bbed-31b0744402ab', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-03-16', '17:30:00', null, '通常 / アレンジ大賞', '「完全に自分で作っていたら時間が足りなくなる」ということで、完成版のコードを見ながらやりました。ただ自分で理解しながらやっていたので、何を作っているのか聞くと毎回答えられていました。移動とジャンプまではほぼ完成して、攻撃やHPの設定は途中までできました。', null, '盛り上がり: ずっと集中してできていました。'),
  ('bd04c4ad-030f-5354-936f-b5911ea2ae57', 'b2246586-4496-52f9-a825-be2488a00a31', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-03-16', '17:30:00', null, '通常 / アレンジ大賞', '今日はとても久しぶりにみんなと同じ題材に取り組んでいました。まずは左右移動とジャンプからやったのですが、座標のことを忘れていてx座標とy座標が紛らわしいようだったので復習して作りました。途中で背景のアレンジをしていたのですが、まずは基本の動きを作ってみようと促しました。「先生、わかんないからヒント出して！」と言われることが多く、あまり多すぎない範囲でヒントをあげました。', null, '盛り上がり: マリオのゲームに興味を持ってくれました。')
on conflict (lesson_record_id) do update set lesson_date = excluded.lesson_date, start_time = excluded.start_time, end_time = excluded.end_time, title = excluded.title, content = excluded.content, homework = excluded.homework, memo = excluded.memo;

commit;
